content:
```json
{
  "action": "build_workflow",
  "commands": [
    {
      "type": "add_node",
      "node_type": "Folder Selector",
      "label": "Select Onboarding PDFs",
      "config": {
        "folderPath": "C:\\incoming\\onboarding",
        "selectionMode": "pattern",
        "filePattern": "*.pdf",
        "outputVariable": "onboardingFiles",
        "failIfEmpty": false
      },
      "position": { "left": "20px", "top": "40px" },
      "node_id": "node-0"
    },
    {
      "type": "add_node",
      "node_type": "Set Variable",
      "label": "Initialize Collected Rows",
      "config": {
        "variableName": "collectedRows",
        "valueSource": "direct",
        "valueExpression": "[]",
        "evaluateAsExpression": true
      },
      "position": { "left": "220px", "top": "40px" },
      "node_id": "node-1"
    },
    {
      "type": "connect_nodes",
      "from": "node-0",
      "to": "node-1",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "Loop",
      "label": "Loop Through PDF Files",
      "config": {
        "sourceType": "auto",
        "loopSource": "${onboardingFiles}",
        "itemVariable": "currentFile",
        "indexVariable": "currentIndex",
        "maxIterations": "10000"
      },
      "position": { "left": "420px", "top": "40px" },
      "node_id": "node-2"
    },
    {
      "type": "connect_nodes",
      "from": "node-1",
      "to": "node-2",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "AI Extract",
      "label": "Extract Customer Fields",
      "config": {
        "inputSource": "auto",
        "inputVariable": "${currentFile}",
        "outputVariable": "extractedCustomer",
        "failOnMissingRequired": false,
        "fields": [
          {
            "name": "customer_name",
            "type": "text",
            "required": false,
            "description": "Customer full name found in the onboarding PDF."
          },
          {
            "name": "customer_email",
            "type": "text",
            "required": false,
            "description": "Customer email address found in the onboarding PDF."
          }
        ]
      },
      "position": { "left": "620px", "top": "20px" },
      "node_id": "node-3"
    },
    {
      "type": "connect_nodes",
      "from": "node-2",
      "to": "node-3",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "Database",
      "label": "Insert Customer Into Database",
      "config": {
        "connection": "5",
        "dbOperation": "query",
        "query": "INSERT INTO dbo.AgentEmailAddresses (email_address, from_name, is_active, created_at)\nVALUES (${extractedCustomer.customer_email}, ${extractedCustomer.customer_name}, 1, GETDATE());",
        "saveToVariable": true,
        "outputVariable": "dbInsertResult",
        "continueOnError": false
      },
      "position": { "left": "820px", "top": "20px" },
      "node_id": "node-4"
    },
    {
      "type": "connect_nodes",
      "from": "node-3",
      "to": "node-4",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "Set Variable",
      "label": "Build Current Row",
      "config": {
        "variableName": "currentRow",
        "valueSource": "direct",
        "valueExpression": "{\"customer_name\": extractedCustomer.get(\"customer_name\"), \"customer_email\": extractedCustomer.get(\"customer_email\"), \"source_file\": currentFile}",
        "evaluateAsExpression": true
      },
      "position": { "left": "1020px", "top": "20px" },
      "node_id": "node-5"
    },
    {
      "type": "connect_nodes",
      "from": "node-4",
      "to": "node-5",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "Set Variable",
      "label": "Append Row To Collection",
      "config": {
        "variableName": "collectedRows",
        "valueSource": "direct",
        "valueExpression": "collectedRows + [currentRow]",
        "evaluateAsExpression": true
      },
      "position": { "left": "1220px", "top": "20px" },
      "node_id": "node-6"
    },
    {
      "type": "connect_nodes",
      "from": "node-5",
      "to": "node-6",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "End Loop",
      "label": "End File Loop",
      "config": {
        "loopNodeId": "node-2"
      },
      "position": { "left": "1420px", "top": "20px" },
      "node_id": "node-7"
    },
    {
      "type": "connect_nodes",
      "from": "node-6",
      "to": "node-7",
      "connection_type": "pass"
    },
    {
      "type": "connect_nodes",
      "from": "node-7",
      "to": "node-2",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "Excel Export",
      "label": "Write Onboarded Excel File",
      "config": {
        "inputVariable": "${collectedRows}",
        "flattenArray": true,
        "excelOutputPath": "onboarded.xlsx",
        "excelOperation": "new",
        "mappingMode": "ai",
        "outputVariable": "excelExportResult"
      },
      "position": { "left": "1620px", "top": "40px" },
      "node_id": "node-8"
    },
    {
      "type": "connect_nodes",
      "from": "node-2",
      "to": "node-8",
      "connection_type": "complete"
    },
    {
      "type": "add_node",
      "node_type": "Set Variable",
      "label": "Prepare Email Body",
      "config": {
        "variableName": "alertMessage",
        "valueSource": "direct",
        "valueExpression": "f\"Customer onboarding workflow completed. Processed {len(collectedRows)} PDF file(s). Excel output: onboarded.xlsx\"",
        "evaluateAsExpression": true
      },
      "position": { "left": "1820px", "top": "40px" },
      "node_id": "node-9"
    },
    {
      "type": "connect_nodes",
      "from": "node-8",
      "to": "node-9",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "Set Variable",
      "label": "Prepare Email Subject",
      "config": {
        "variableName": "alertSubject",
        "valueSource": "direct",
        "valueExpression": "Customer onboarding completed",
        "evaluateAsExpression": false
      },
      "position": { "left": "2020px", "top": "40px" },
      "node_id": "node-10"
    },
    {
      "type": "connect_nodes",
      "from": "node-9",
      "to": "node-10",
      "connection_type": "pass"
    },
    {
      "type": "add_node",
      "node_type": "Alert",
      "label": "Email CRM Team",
      "config": {
        "alertType": "email",
        "recipients": "crm@acme.com",
        "emailSubject": "${alertSubject}",
        "messageTemplate": "${alertMessage}",
        "attachmentPath": "onboarded.xlsx"
      },
      "position": { "left": "2220px", "top": "40px" },
      "node_id": "node-11"
    },
    {
      "type": "connect_nodes",
      "from": "node-10",
      "to": "node-11",
      "connection_type": "pass"
    },
    {
      "type": "set_start_node",
      "node_id": "node-0"
    }
  ]
}
```
